import type { Metadata } from 'next';
import Link from 'next/link';
import { notFound } from 'next/navigation';

type Post = {
  id: number;
  title: string;
  body: string;
};

type Comment = {
  id: number;
  name: string;
  body: string;
  email: string;
};

type Params = { id: string };

async function getPost(id: string): Promise<Post | null> {
  const response = await fetch(`https://jsonplaceholder.typicode.com/posts/${id}`, {
    next: { revalidate: 300 },
  });

  if (!response.ok) return null;
  return response.json();
}

async function getComments(id: string): Promise<Comment[]> {
  const response = await fetch(`https://jsonplaceholder.typicode.com/posts/${id}/comments`, {
    next: { revalidate: 300 },
  });
  return response.json();
}

export async function generateStaticParams(): Promise<Params[]> {
  const response = await fetch('https://jsonplaceholder.typicode.com/posts');
  const posts: Post[] = await response.json();
  return posts.slice(0, 10).map((post) => ({ id: String(post.id) }));
}

export async function generateMetadata({ params }: { params: Promise<Params> }): Promise<Metadata> {
  const { id } = await params;
  const post = await getPost(id);

  if (!post) return { title: 'Post Not Found - My Blog' };

  return {
    title: `${post.title} - My Blog`,
    description: post.body.substring(0, 160),
    openGraph: {
      title: post.title,
      description: post.body.substring(0, 160),
    },
  };
}

export default async function BlogPostPage({ params }: { params: Promise<Params> }) {
  const { id } = await params;
  const [post, comments] = await Promise.all([getPost(id), getComments(id)]);

  if (!post) {
    notFound();
  }

  return (
    <article>
      <Link href="/blog" className="button-link">
        ← Back
      </Link>

      <h1>{post.title}</h1>
      <p>{post.body}</p>

      <h2>Comments ({comments.length})</h2>
      <div className="comments">
        {comments.map((comment) => (
          <div key={comment.id} className="comment">
            <h3>{comment.name}</h3>
            <p>{comment.body}</p>
            <small>By: {comment.email}</small>
          </div>
        ))}
      </div>
    </article>
  );
}
